export function getTechIcon(tech: string): string {
    if (!tech) return "/tech-stack/Devicon.png";

    const normalized = tech.toLowerCase().trim();
    
    // Try exact mapping
    if (MAPPING[normalized]) {
        return `/tech-stack/${MAPPING[normalized]}`;
    }

    // Try normalized name mapping (remove spaces, hyphens, dots)
    const clean = normalized.replace(/[^a-z0-9]/g, '');
    if (MAPPING[clean]) {
        return `/tech-stack/${MAPPING[clean]}`;
    }

    // Default general fallback icon
    return "/tech-stack/Devicon.png";
}
